example.code:
[
  {
    "type": "stat",
    "title": "Request Rate",
    "targets": [{"expr": "sum(rate(http_requests_total{namespace=\"$namespace\"}[$interval]))", "legendFormat": "req/s"}],
    "fieldConfig": {"defaults": {"unit": "reqps", "thresholds": {"steps": [
      {"color": "green", "value": null},
      {"color": "yellow", "value": 1000},
      {"color": "red", "value": 5000}
    ]}}}
  },
  {
    "type": "stat",
    "title": "Error Rate",
    "targets": [{"expr": "sum(rate(http_requests_total{namespace=\"$namespace\",status=~\"5..\"}[$interval])) / sum(rate(http_requests_total{namespace=\"$namespace\"}[$interval])) * 100"}],
    "fieldConfig": {"defaults": {"unit": "percent", "thresholds": {"steps": [
      {"color": "green", "value": null},
      {"color": "yellow", "value": 1},
      {"color": "red", "value": 5}
    ]}}}
  },
  {
    "type": "stat",
    "title": "P99 Latency",
    "targets": [{"expr": "histogram_quantile(0.99, sum(rate(http_request_duration_seconds_bucket{namespace=\"$namespace\"}[$interval])) by (le))"}],
    "fieldConfig": {"defaults": {"unit": "s", "thresholds": {"steps": [
      {"color": "green", "value": null},
      {"color": "yellow", "value": 0.5},
      {"color": "red", "value": 1}
    ]}}}
  }
]

{
  "type": "gauge",
  "title": "Availability SLO (99.9%)",
  "description": "30-day rolling availability against 99.9% SLO target",
  "targets": [{
    "expr": "(1 - sum(rate(http_requests_total{namespace=\"$namespace\",status=~\"5..\"}[30d])) / sum(rate(http_requests_total{namespace=\"$namespace\"}[30d]))) * 100"
  }],
  "options": {"showThresholdMarkers": true},
  "fieldConfig": {
    "defaults": {
      "unit": "percent",
      "min": 99,
      "max": 100,
      "thresholds": {"mode": "absolute", "steps": [
        {"color": "red", "value": null},
        {"color": "yellow", "value": 99.5},
        {"color": "green", "value": 99.9}
      ]}
    }
  }
}
